def is_connected(G):
    if not G:
        return True
    visited = set()
    start = next(iter(G))  # 取任意顶点

    def dfs(v):
        visited.add(v)
        for neighbor in G[v]:
            if neighbor not in visited:
                dfs(neighbor)

    dfs(start)
    return len(visited) == len(G)
```

复杂度：O(V + E)

